update public.lessons l set enhancements = $ench${"industryStory":"A capable tester got no callbacks. Their CV opened with a generic objective and buried QA skills on page two. One rewrite — sharp summary, skills up top, portfolio linked — and interviews started arriving. Recruiters scan; the CV has seconds to land.","badGood":{"label":"a CV summary","bad":"\"Hard-working individual seeking an opportunity to grow in a dynamic company.\"","good":"\"Detail-driven QA tester with hands-on test design, defect management, API testing (Postman) and SQL. Built a public QA portfolio; focused on preventing defects early.\""},"davidTip":"A reviewer scans the top third first — put a sharp summary and key skills there, and link your portfolio. Keep it to one or two pages, achievement-led, and proofread relentlessly: a typo on a QA CV is the worst first impression.","miniChallenge":"Write your two-to-three line QA CV summary, leading with your strongest relevant skills, and add your portfolio link.","modelAnswer":"## Example\n\"QA tester focused on practical, risk-based testing. Hands-on with test design techniques, professional defect reporting, API testing in Postman and SQL validation. Portfolio: [link].\"","resourcePreview":{"name":"QA CV / Résumé Template","purpose":"A clean, recruiter-ready CV structure tailored for testing roles.","whenToUse":"Use it to structure or rewrite your CV.","formats":["DOCX","PDF"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 7 and l.lesson_number = 1;

update public.lessons l set enhancements = $ench${"industryStory":"A recruiter searched LinkedIn for \"QA automation Agile\" and a strong candidate never appeared — one-line headline, empty About. Optimising LinkedIn is what gets you found, not just seen.","badGood":{"label":"a LinkedIn headline","bad":"\"Looking for opportunities\"","good":"\"QA Tester | Manual & Automation | Agile · Jira · API · SQL | QA portfolio in bio\""},"davidTip":"Recruiters search by keyword. If \"QA\", \"automation\", \"API\" and \"Agile\" appear naturally in your headline and About, you surface in far more searches. Write the About in the first person and pin your portfolio to Featured.","miniChallenge":"Rewrite your LinkedIn headline (role + value + keywords) and draft the first two lines of your About.","modelAnswer":"## Example\nHeadline: \"Software Tester | Manual + Automation | Agile · Jira · API · SQL | QA portfolio in bio\". About opener: \"I'm a detail-driven tester focused on preventing defects early and communicating quality clearly. I've built a portfolio covering test design, defects, API testing and SQL…\"","resourcePreview":{"name":"LinkedIn Profile Optimisation Guide for Testers","purpose":"Section-by-section guide to a recruiter-friendly profile.","whenToUse":"Work through it to optimise each part of your profile.","formats":["PDF","DOCX"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 7 and l.lesson_number = 2;

update public.lessons l set enhancements = $ench${"industryStory":"A candidate sent the same generic CV to 50 roles and heard nothing. Switching to tailored top-thirds and tracking every application, their response rate jumped — and they stopped losing track of follow-ups.","davidTip":"You do not need a new CV per job — a strong base plus a tailored top third. Mirror the job's language (honestly), and track every application with a next action. Most candidates never follow up; doing so sets you apart.","miniChallenge":"Take a real QA job ad, pull five keywords, and note how you would adjust your CV's top third; then set up a simple application tracker.","modelAnswer":"## Example\nJD stresses \"API testing, Agile, regression\" → I lead my summary with those, reorder skills, and mirror the terms in my bullets. Tracker columns: company, role, date applied, status, next action + date.","resourcePreview":{"name":"Job Search Tracker Template","purpose":"Keep every application, contact and follow-up organised.","whenToUse":"Set it up before you start applying.","formats":["XLSX","DOCX"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 7 and l.lesson_number = 3;

update public.lessons l set enhancements = $ench${"davidTip":"For this assignment, make your CV and LinkedIn consistent, achievement-led, and portfolio-linked. The \"six-second test\" — can a stranger see your role, top skills and portfolio almost instantly? — is the bar to hit.","miniChallenge":"Before submitting, run the six-second test on your CV and fix anything a stranger could not grasp that fast.","managersReview":{"intro":"If I received your CV and LinkedIn as a hiring manager, I would look for:","strengths":["Sharp summary and skills up top","Achievement bullets with outcomes","Portfolio linked; consistent CV/LinkedIn"],"gaps":["Generic objective and duty bullets","No metrics or portfolio link","Typos"],"improvements":["Lead with relevant skills","Quantify achievements","Link the portfolio and proofread"]},"portfolioBuilder":"Your CV, LinkedIn and portfolio should tell one consistent story — that package is what you take to the market in the final module."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 7 and l.lesson_number = 4;

